db:select.db:input-parameters:
#[{
                pageSize: vars.pageSize as Number,
                offset: ((vars.page as Number) - 1) * (vars.pageSize as Number)
            }]

db:insert.db:input-parameters:
#[{
                entityId: vars.newPolicyId as String,
                actor: vars.policyData.holderEmail default "system",
                details: "Policy " ++ (vars.policyData.policyNumber default "") ++ " created. Type: " ++ (vars.policyData.policyType default "") ++ ", Coverage: $" ++ (vars.policyData.coverageAmount as String default "0")
            }]

#[{
                        entityId: vars.policyId as String,
                        details: "Policy updated. New coverage: $" ++ (vars.updateData.coverageAmount as String default "0")
                    }]

#[{
                                entityId: vars.newClaimId as String,
                                actor: vars.claimData.claimantName,
                                details: "Claim " ++ vars.claimNumber ++ " filed. Amount: $" ++ (vars.claimData.claimAmount as String) ++ ", Type: " ++ (vars.claimData.claimType default "")
                            }]

#[{
                        entityId: vars.claimId as String,
                        details: "Claim approved. Amount: $" ++ (vars.statusData.approvedAmount as String default "0")
                    }]

#[{
                        entityId: vars.claimId as String,
                        details: "Claim rejected. Reason: " ++ (vars.statusData.reason default "Not specified")
                    }]

#[{
                        entityId: vars.claimId as String,
                        actor: attributes.headers.'x-uploaded-by' default "api-user",
                        details: "Document uploaded: " ++ vars.fileName ++ " for claim " ++ (vars.claimInfo.claim_number default "")
                    }]

ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
  success: true,
  message: "Document uploaded successfully",
  document: {
    fileName: vars.fileName,
    filePath: vars.filePath,
    claimId: vars.claimId,
    claimNumber: vars.claimInfo.claim_number
  }
}

%dw 2.0
output application/json
---
{
  success: true,
  dashboard: {
    totalClaims: payload."0".payload[0].total_claims,
    claimsByStatus: payload."1".payload reduce ((item, acc = {}) ->
      acc ++ { (item.status): { count: item.count, totalAmount: item.total_amount } }
    ),
    financials: {
      totalClaimed: payload."2".payload[0].total_claimed,
      totalApproved: payload."2".payload[0].total_approved,
      averageClaim: payload."2".payload[0].avg_claim,
      approvalRate: if (payload."2".payload[0].total_claimed > 0)
                      (payload."2".payload[0].total_approved / payload."2".payload[0].total_claimed * 100)
                    else 0
    },
    policies: {
      activePolicies: payload."3".payload[0].active_policies,
      totalCoverage: payload."3".payload[0].total_coverage,
      totalPremiums: payload."3".payload[0].total_premiums
    },
    recentActivity: payload."4".payload map {
      action: $.action,
      count: $.count
    },
    documents: {
      totalDocuments: payload."5".payload[0].total_documents,
      totalStorageBytes: payload."5".payload[0].total_storage_bytes,
      totalStorageMB: payload."5".payload[0].total_storage_bytes / 1048576,
      claimsWithDocuments: payload."5".payload[0].claims_with_docs
    }
  }
}

%dw 2.0
output application/json
---
{
  success: true,
  report: {
    month: vars.month,
    generatedAt: now() as String {format: "yyyy-MM-dd'T'HH:mm:ss'Z'"},
    claimsSummary: payload."0".payload map {
      claimType: $.claim_type,
      count: $.count,
      totalAmount: $.total_amount,
      totalApproved: $.total_approved
    },
    newPolicies: payload."1".payload map {
      policyType: $.policy_type,
      count: $.count,
      totalCoverage: $.total_coverage,
      totalPremium: $.total_premium
    },
    topClaimants: payload."2".payload map {
      name: $.claimant_name,
      claimsCount: $.claims_count,
      totalClaimed: $.total_claimed
    }
  }
}

%dw 2.0
output application/json
---
{
  success: true,
  count: sizeOf(payload),
  filter: {
    entityType: vars.entityType,
    days: vars.days as Number
  },
  auditLog: payload map {
    id: $.id,
    entityType: $.entity_type,
    entityId: $.entity_id,
    action: $.action,
    actor: $.actor,
    details: $.details,
    timestamp: $.created_at
  }
}

%dw 2.0
output application/json
var allUp = (payload."0".payload == "UP") and (payload."1".payload == "UP")
            and (payload."2".payload == "UP") and (payload."3".payload == "UP")
---
{
  status: if (allUp) "UP" else "DEGRADED",
  service: "Insurance Claims API",
  version: "2.0.0",
  environment: p('mule.env'),
  timestamp: now() as String {format: "yyyy-MM-dd'T'HH:mm:ss'Z'"},
  dependencies: {
    claimsDatabase: { status: payload."0".payload, type: "MySQL" },
    auditDatabase: { status: payload."1".payload, type: "PostgreSQL" },
    documentsDatabase: { status: payload."2".payload, type: "SQL Server" },
    fileShare: { status: payload."3".payload, type: "Azure File Share" }
  }
}

%dw 2.0
output application/json
---
{
    success: true,
    source: "jsonplaceholder.typicode.com (mock CRM)",
    totalUsers: sizeOf(payload),
    users: payload map ((user) -> {
        id: user.id,
        name: user.name,
        email: user.email,
        phone: user.phone,
        company: user.company.name default "N/A",
        address: {
            street: user.address.street default "",
            city: user.address.city default "",
            zipcode: user.address.zipcode default "",
            geo: user.address.geo default {}
        }
    })
}

%dw 2.0
output application/json
---
{
    success: true,
    source: "jsonplaceholder.typicode.com (mock CRM)",
    user: {
        id: payload."0".payload.id,
        name: payload."0".payload.name,
        email: payload."0".payload.email,
        phone: payload."0".payload.phone,
        company: payload."0".payload.company.name default "N/A"
    },
    recentPosts: (payload."1".payload default []) map ((post) -> {
        id: post.id,
        title: post.title
    }),
    pendingTasks: sizeOf((payload."2".payload default []) filter ((todo) -> todo.completed == false)),
    completedTasks: sizeOf((payload."2".payload default []) filter ((todo) -> todo.completed == true))
}

